CREATE SCHEMA IF NOT EXISTS vibecoding;

CREATE TABLE IF NOT EXISTS vibecoding.customers (
    id UUID PRIMARY KEY,
    name VARCHAR(255) NOT NULL,
    email VARCHAR(255) NOT NULL UNIQUE,
    tier VARCHAR(50) NOT NULL
);

CREATE TABLE IF NOT EXISTS vibecoding.events (
    id UUID PRIMARY KEY,
    name VARCHAR(255) NOT NULL,
    artist VARCHAR(255) NOT NULL,
    location VARCHAR(255) NOT NULL,
    date_time TIMESTAMP NOT NULL,
    available_tickets INTEGER NOT NULL,
    base_price NUMERIC(19, 2) NOT NULL
);

CREATE TABLE IF NOT EXISTS vibecoding.bookings (
    id UUID PRIMARY KEY,
    customer_id UUID NOT NULL REFERENCES vibecoding.customers(id),
    event_id UUID NOT NULL REFERENCES vibecoding.events(id),
    total_amount NUMERIC(19, 2) NOT NULL,
    status VARCHAR(50) NOT NULL,
    created_at TIMESTAMP NOT NULL
);

CREATE TABLE IF NOT EXISTS vibecoding.tickets (
    id UUID PRIMARY KEY,
    booking_id UUID NOT NULL REFERENCES vibecoding.bookings(id),
    event_id UUID NOT NULL REFERENCES vibecoding.events(id),
    ticket_code VARCHAR(255) NOT NULL UNIQUE
);

