import wingorithm.ticketing.vibecoding.domain.event.Event;
import wingorithm.ticketing.vibecoding.infrastructure.persistence.event.EventRepository;
import wingorithm.ticketing.vibecoding.presentation.dto.EventResponse;

import java.util.List;
import java.util.stream.Collectors;

@Service
@RequiredArgsConstructor
@Transactional(readOnly = true)
public class EventSearchService {

    private final EventRepository eventRepository;

    public List<EventResponse> searchEvents(String query) {
        List<Event> events;

        if (query == null || query.trim().isEmpty()) {
            events = eventRepository.findAll();
        } else {
            // Search across both artist and location using the same query keyword
            events = eventRepository.findByArtistContainingIgnoreCaseOrLocationContainingIgnoreCase(query, query);
        }

        return events.stream()
                .map(this::mapToResponse)
                .collect(Collectors.toList());
    }

    private EventResponse mapToResponse(Event event) {
        return EventResponse.builder()
                .id(event.getId())
                .name(event.getName())
                .artist(event.getArtist())
                .location(event.getLocation())
                .dateTime(event.getDateTime())
                .availableTickets(event.getAvailableTickets())
                .basePrice(event.getBasePrice())
                .build();
    }
}

