import static org.mockito.Mockito.when;

@ExtendWith(MockitoExtension.class)
class EventSearchServiceTest {

    @Mock
    private EventRepository eventRepository;

    @InjectMocks
    private EventSearchService eventSearchService;

    private Event mockEvent;

    @BeforeEach
    void setUp() {
        mockEvent = Event.builder()
                .id(UUID.randomUUID())
                .name("Summer Vibe Festival")
                .artist("The Vibe Band")
                .location("Jakarta Stadium")
                .dateTime(LocalDateTime.now().plusDays(30))
                .availableTickets(500)
                .basePrice(new BigDecimal("150000.00"))
                .build();
    }

    @Test
    void searchEvents_Positive_ShouldReturnMatchingEvents() {
        // Arrange
        String query = "Jakarta";
        when(eventRepository.findByArtistContainingIgnoreCaseOrLocationContainingIgnoreCase(query, query))
                .thenReturn(List.of(mockEvent));

        // Act
        List<EventResponse> result = eventSearchService.searchEvents(query);

        // Assert
        assertEquals(1, result.size());
        assertEquals("Jakarta Stadium", result.get(0).getLocation());
        assertEquals("The Vibe Band", result.get(0).getArtist());
    }

    @Test
    void searchEvents_Negative_ShouldReturnEmptyListWhenNoMatch() {
        // Arrange
        String query = "UnknownArtist";
        when(eventRepository.findByArtistContainingIgnoreCaseOrLocationContainingIgnoreCase(anyString(), anyString()))
                .thenReturn(Collections.emptyList());

        // Act
        List<EventResponse> result = eventSearchService.searchEvents(query);

        // Assert
        assertTrue(result.isEmpty(), "Expected an empty list when no events match the search query");
    }
}

